<template>
    <div class="knockout">
        <div class="bracket">
            <div v-for="round in rounds" :key="round.key" class="round-column">
                <h3 class="round-title">{{ round.title }}</h3>
                <div
                    v-for="match in round.matches"
                    :key="match.num"
                    class="match-card"
                    :class="{ decided: !!match.winner }"
                >
                    <div class="match-no">Mecz {{ match.num }}</div>

                    <div class="team-row" :class="{ winner: isWinner(match, 'team1') }">
                        <flag v-if="match.team1" :iso="match.team1.icon" />
                        <span v-else class="flag-placeholder" />
                        <span class="tname">{{ match.team1 ? match.team1.name : 'Do ustalenia' }}</span>
                        <v-text-field
                            type="number"
                            min="0"
                            variant="outlined"
                            hide-details
                            density="compact"
                            class="goal-input"
                            :model-value="match.goals1"
                            :disabled="!match.team1 || !match.team2"
                            @update:modelValue="(value) => setGoals(match.num, 'team1', value)"
                        />
                    </div>

                    <div class="team-row" :class="{ winner: isWinner(match, 'team2') }">
                        <flag v-if="match.team2" :iso="match.team2.icon" />
                        <span v-else class="flag-placeholder" />
                        <span class="tname">{{ match.team2 ? match.team2.name : 'Do ustalenia' }}</span>
                        <v-text-field
                            type="number"
                            min="0"
                            variant="outlined"
                            hide-details
                            density="compact"
                            class="goal-input"
                            :model-value="match.goals2"
                            :disabled="!match.team1 || !match.team2"
                            @update:modelValue="(value) => setGoals(match.num, 'team2', value)"
                        />
                    </div>

                    <div v-if="match.isDraw" class="penalty-row">
                        <button
                            type="button"
                            class="penalty-btn"
                            :class="{ active: match.penaltyWinner === 'team1' }"
                            @click="setPenalty(match.num, 'team1')"
                        >
                            {{ match.team1.name }} – karne
                        </button>
                        <button
                            type="button"
                            class="penalty-btn"
                            :class="{ active: match.penaltyWinner === 'team2' }"
                            @click="setPenalty(match.num, 'team2')"
                        >
                            {{ match.team2.name }} – karne
                        </button>
                    </div>
                </div>
            </div>
        </div>

        <div class="champion-banner" :class="{ crowned: !!champion }">
            <span class="champion-kicker">Mistrz Swiata 2026</span>
            <div class="champion-team" v-if="champion">
                <flag :iso="champion.icon" />
                <strong>{{ champion.name }}</strong>
            </div>
            <div class="champion-team placeholder" v-else>
                <strong>Wpisz wyniki, aby wylonic mistrza</strong>
            </div>
        </div>
    </div>
</template>
<script>
const KNOCKOUT_STORAGE_KEY = 'worldcup-cup-state-v1';

const ROUND_OF_32 = [73, 74, 75, 76, 77, 78, 79, 80, 81, 82, 83, 84, 85, 86, 87, 88];
const ROUND_OF_16 = [89, 90, 91, 92, 93, 94, 95, 96];
const QUARTERFINALS = [97, 98, 99, 100];
const SEMIFINALS = [101, 102];
const THIRD_PLACE = 103;
const FINAL = 104;

const R16_FEEDERS = {
    89: [74, 77],
    90: [73, 75],
    91: [76, 78],
    92: [79, 80],
    93: [83, 84],
    94: [81, 82],
    95: [86, 88],
    96: [85, 87]
};

const QF_FEEDERS = {
    97: [89, 90],
    98: [93, 94],
    99: [91, 92],
    100: [95, 96]
};

const SF_FEEDERS = {
    101: [97, 98],
    102: [99, 100]
};

const ALL_MATCH_NUMBERS = [
    ...ROUND_OF_32,
    ...ROUND_OF_16,
    ...QUARTERFINALS,
    ...SEMIFINALS,
    THIRD_PLACE,
    FINAL
];

const createScores = () => {
    return ALL_MATCH_NUMBERS.reduce((acc, num) => {
        acc[num] = { goals1: 0, goals2: 0, penaltyWinner: null };
        return acc;
    }, {});
};

export default {
    name: 'WorldCupKnockout',
    props: {
        round32: {
            type: Array,
            required: true
        },
        addGoalsScored: {
            type: Function,
            required: true
        }
    },
    data() {
        return {
            scores: createScores(),
            emittedByKey: {}
        };
    },
    computed: {
        round32ByNumber() {
            return this.round32.reduce((acc, match) => {
                acc[match.num] = match;
                return acc;
            }, {});
        },
        resolvedMatches() {
            const result = {};
            const scoreOf = (num) => this.scores[num] || { goals1: 0, goals2: 0, penaltyWinner: null };

            ROUND_OF_32.forEach((num) => {
                const seed = this.round32ByNumber[num] || { team1: null, team2: null };
                const score = scoreOf(num);
                const decided = this.decideMatch(seed.team1, seed.team2, score.goals1, score.goals2, score.penaltyWinner);
                result[num] = {
                    team1: seed.team1 || null,
                    team2: seed.team2 || null,
                    winner: decided.winner,
                    loser: decided.loser
                };
            });

            const buildFromFeeders = (num, feederA, feederB, useLosers) => {
                const team1 = useLosers ? result[feederA].loser : result[feederA].winner;
                const team2 = useLosers ? result[feederB].loser : result[feederB].winner;
                const score = scoreOf(num);
                const decided = this.decideMatch(team1, team2, score.goals1, score.goals2, score.penaltyWinner);
                result[num] = {
                    team1: team1 || null,
                    team2: team2 || null,
                    winner: decided.winner,
                    loser: decided.loser
                };
            };

            Object.entries(R16_FEEDERS).forEach(([num, [a, b]]) => buildFromFeeders(Number(num), a, b, false));
            Object.entries(QF_FEEDERS).forEach(([num, [a, b]]) => buildFromFeeders(Number(num), a, b, false));
            Object.entries(SF_FEEDERS).forEach(([num, [a, b]]) => buildFromFeeders(Number(num), a, b, false));
            buildFromFeeders(THIRD_PLACE, SEMIFINALS[0], SEMIFINALS[1], true);
            buildFromFeeders(FINAL, SEMIFINALS[0], SEMIFINALS[1], false);

            return result;
        },
        rounds() {
            return [
                { key: 'r32', title: '1/16 finalu', matches: this.buildRound(ROUND_OF_32) },
                { key: 'r16', title: '1/8 finalu', matches: this.buildRound(ROUND_OF_16) },
                { key: 'qf', title: 'Cwiercfinaly', matches: this.buildRound(QUARTERFINALS) },
                { key: 'sf', title: 'Polfinaly', matches: this.buildRound(SEMIFINALS) },
                { key: 'final', title: 'Final', matches: this.buildRound([FINAL]) },
                { key: 'third', title: 'Mecz o 3. miejsce', matches: this.buildRound([THIRD_PLACE]) }
            ];
        },
        champion() {
            return this.resolvedMatches[FINAL] ? this.resolvedMatches[FINAL].winner : null;
        }
    },
    methods: {
        normalizeGoals(value) {
            const parsed = Number.parseInt(value, 10);
            return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
        },
        decideMatch(team1, team2, goals1, goals2, penaltyWinner) {
            if (!team1 || !team2) {
                return { winner: null, loser: null };
            }

            const g1 = this.normalizeGoals(goals1);
            const g2 = this.normalizeGoals(goals2);

            if (g1 > g2) {
                return { winner: team1, loser: team2 };
            }

            if (g2 > g1) {
                return { winner: team2, loser: team1 };
            }

            if (penaltyWinner === 'team1') {
                return { winner: team1, loser: team2 };
            }

            if (penaltyWinner === 'team2') {
                return { winner: team2, loser: team1 };
            }

            return { winner: null, loser: null };
        },
        buildRound(numbers) {
            return numbers.map((num) => {
                const resolved = this.resolvedMatches[num] || { team1: null, team2: null, winner: null };
                const score = this.scores[num] || { goals1: 0, goals2: 0, penaltyWinner: null };
                const bothPresent = !!resolved.team1 && !!resolved.team2;

                return {
                    num,
                    team1: resolved.team1,
                    team2: resolved.team2,
                    goals1: score.goals1,
                    goals2: score.goals2,
                    penaltyWinner: score.penaltyWinner,
                    isDraw: bothPresent && this.normalizeGoals(score.goals1) === this.normalizeGoals(score.goals2),
                    winner: resolved.winner
                };
            });
        },
        isWinner(match, side) {
            const team = side === 'team1' ? match.team1 : match.team2;
            return !!match.winner && !!team && match.winner.name === team.name;
        },
        setGoals(num, side, value) {
            const current = this.scores[num];

            if (!current) {
                return;
            }

            const normalized = this.normalizeGoals(value);
            const updated = {
                goals1: side === 'team1' ? normalized : current.goals1,
                goals2: side === 'team2' ? normalized : current.goals2,
                penaltyWinner: current.penaltyWinner
            };

            if (updated.goals1 !== updated.goals2) {
                updated.penaltyWinner = null;
            }

            this.scores = { ...this.scores, [num]: updated };
        },
        setPenalty(num, side) {
            const current = this.scores[num];

            if (!current) {
                return;
            }

            this.scores = {
                ...this.scores,
                [num]: { ...current, penaltyWinner: side }
            };
        },
        emitGoalsForKey(sourceKey, team, goals) {
            if (!team) {
                const previousTeam = this.emittedByKey[sourceKey];

                if (previousTeam) {
                    this.addGoalsScored(0, previousTeam, sourceKey);
                    delete this.emittedByKey[sourceKey];
                }

                return;
            }

            this.emittedByKey[sourceKey] = team.name;
            this.addGoalsScored(this.normalizeGoals(goals), team.name, sourceKey);
        },
        emitAllGoals() {
            Object.entries(this.resolvedMatches).forEach(([num, match]) => {
                const score = this.scores[num] || { goals1: 0, goals2: 0 };
                this.emitGoalsForKey(`wc-cup-${num}-team1`, match.team1, score.goals1);
                this.emitGoalsForKey(`wc-cup-${num}-team2`, match.team2, score.goals2);
            });
        },
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        saveState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                window.localStorage.setItem(KNOCKOUT_STORAGE_KEY, JSON.stringify(this.scores));
            } catch (error) {
                void error;
            }
        },
        loadState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const raw = window.localStorage.getItem(KNOCKOUT_STORAGE_KEY);

                if (!raw) {
                    return;
                }

                const parsed = JSON.parse(raw);
                const restored = createScores();

                ALL_MATCH_NUMBERS.forEach((num) => {
                    const stored = parsed[num];

                    if (!stored || typeof stored !== 'object') {
                        return;
                    }

                    restored[num] = {
                        goals1: this.normalizeGoals(stored.goals1),
                        goals2: this.normalizeGoals(stored.goals2),
                        penaltyWinner: stored.penaltyWinner === 'team1' || stored.penaltyWinner === 'team2'
                            ? stored.penaltyWinner
                            : null
                    };
                });

                this.scores = restored;
            } catch (error) {
                void error;
            }
        }
    },
    mounted() {
        this.loadState();
        this.emitAllGoals();
    },
    watch: {
        scores: {
            handler() {
                this.saveState();
                this.emitAllGoals();
            },
            deep: true
        }
    }
};
</script>
<style scoped>
.knockout {
    margin-top: 8px;
}

.bracket {
    display: flex;
    gap: 16px;
    overflow-x: auto;
    padding-bottom: 12px;
    align-items: flex-start;
}

.round-column {
    flex: 0 0 auto;
    width: 240px;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.round-title {
    margin: 0;
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
    font-size: 1.25rem;
    color: #14213d;
    position: sticky;
    top: 0;
}

.match-card {
    border-radius: 14px;
    border: 1px solid rgba(20, 33, 61, 0.12);
    background: #ffffff;
    padding: 10px;
    box-shadow: 0 6px 16px rgba(20, 33, 61, 0.08);
}

.match-card.decided {
    border-color: rgba(54, 150, 83, 0.55);
}

.match-no {
    font-size: 0.7rem;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    opacity: 0.55;
    margin-bottom: 6px;
}

.team-row {
    display: grid;
    grid-template-columns: 18px 1fr 64px;
    align-items: center;
    gap: 8px;
    padding: 4px;
    border-radius: 8px;
}

.team-row + .team-row {
    margin-top: 4px;
}

.team-row.winner {
    background: rgba(54, 150, 83, 0.12);
}

.team-row.winner .tname {
    font-weight: 700;
}

.flag-placeholder {
    width: 18px;
    height: 12px;
    border-radius: 2px;
    background: rgba(20, 33, 61, 0.12);
}

.tname {
    font-size: 0.86rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.goal-input {
    width: 64px;
}

.penalty-row {
    display: flex;
    flex-direction: column;
    gap: 4px;
    margin-top: 8px;
}

.penalty-btn {
    font-size: 0.72rem;
    padding: 4px 8px;
    border-radius: 999px;
    border: 1px solid rgba(20, 33, 61, 0.25);
    background: transparent;
    cursor: pointer;
    transition: all 0.15s ease;
    text-align: center;
}

.penalty-btn:hover {
    border-color: #369653;
}

.penalty-btn.active {
    background: #369653;
    border-color: #369653;
    color: #ffffff;
    font-weight: 700;
}

.champion-banner {
    margin-top: 22px;
    padding: 20px 24px;
    border-radius: 20px;
    background: linear-gradient(130deg, #14213d, #1f4068 55%, #c9a227);
    color: #ffffff;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    box-shadow: 0 14px 36px rgba(20, 33, 61, 0.3);
}

.champion-kicker {
    letter-spacing: 0.16em;
    text-transform: uppercase;
    font-size: 0.82rem;
    opacity: 0.9;
}

.champion-team {
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 1.8rem;
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
}

.champion-team.placeholder {
    font-size: 1.05rem;
    opacity: 0.85;
}

@media (max-width: 700px) {
    .round-column {
        width: 210px;
    }
}
</style>
