<template>
    <div class="login-page">
        <v-card class="login-card" rounded="xl" elevation="12">
            <v-card-text class="pa-6">
                <div class="logo-wrap">
                    <v-img :src="TrophyPhoto" width="130" class="mb-4" />
                    <h1>Tournament App</h1>
                    <p>Zaloguj sie, aby rozpoczec losowanie i wpisywanie wynikow.</p>
                </div>
                <v-text-field
                    label="Username"
                    variant="outlined"
                    v-model="username"
                    prepend-inner-icon="mdi-account"
                    @keyup.enter="login"
                >
                </v-text-field>
                <v-text-field
                    label="Password"
                    variant="outlined"
                    :type="showPassword ? 'text' : 'password'"
                    v-model="password"
                    prepend-inner-icon="mdi-lock"
                    @keyup.enter="login"
                >
                    <template v-slot:append-inner>
                        <v-icon @click="showPassword = !showPassword">
                            {{ showPassword ? 'mdi-eye-off' : 'mdi-eye' }}
                        </v-icon>
                    </template>
                </v-text-field>
                <v-btn
                    color="primary"
                    @click="login"
                    :loading="loading"
                    width="100%"
                    rounded="lg"
                >
                    Login
                </v-btn>
                <div class="hint">Demo: 3zjby / karolToGej</div>
            </v-card-text>
        </v-card>
    </div>
</template>
<script>
import TrophyPhoto from '@/assets/trophy.png'
import { toast } from "vue3-toastify";
import "vue3-toastify/dist/index.css";

export default {
    name: 'LoginPage',
    data() {
        return {
            TrophyPhoto,
            username: '',
            password: '',
            showPassword: false,
            loading: false
        }
    },
    methods: {
        async login() {
            this.loading = true
            if (this.username === '3zjby' && this.password === 'karolToGej') {
                localStorage.setItem('user', this.username)
                await new Promise((resolve) => setTimeout(resolve, 700));
                this.loading = false;
                this.$router.push({ name: 'Home' });
            } else {
                toast('Invalid username or password', {
                    type: 'error'
                })
                this.loading = false
            }
        }
    }
}
</script>
<style scoped>
.login-page {
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 20px;
}

.login-card {
    width: 100%;
    max-width: 420px;
    backdrop-filter: blur(4px);
    border: 1px solid rgba(255, 255, 255, 0.4);
}

.logo-wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
}

.logo-wrap h1 {
    margin: 0;
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.04em;
    font-size: 2rem;
}

.logo-wrap p {
    margin: 6px 0 16px;
    opacity: 0.75;
}

.hint {
    text-align: center;
    margin-top: 12px;
    font-size: 0.82rem;
    opacity: 0.65;
}
</style>