<template>
    <div class="worldcup-wrapper">
        <section class="hero">
            <div class="hero-top">
                <span class="hero-kicker">Edycja specjalna</span>
                <v-btn
                    variant="text"
                    color="white"
                    rounded="xl"
                    prepend-icon="mdi-arrow-left"
                    :to="{ name: 'Home' }"
                >
                    Powrot
                </v-btn>
            </div>
            <h1>Mistrzostwa Swiata 2026</h1>
            <p>Grupy i druzyny sa juz ustawione dokladnie tak, jak na MS 2026. Losuj kraje miedzy graczy i wpisuj wyniki.</p>
            <div class="hero-actions">
                <v-btn color="primary" size="x-large" rounded="xl" prepend-icon="mdi-dice-multiple" @click="roll">
                    Losuj Kraje
                </v-btn>
                <span class="stats-chip">48 druzyn &middot; 12 grup</span>
                <span class="stats-chip" v-if="isDrafted">Wszystkie gole: {{ totalGoals }}</span>
            </div>
        </section>

        <section class="draft-section" v-if="isDrafted">
            <h2>Wylosowane kraje</h2>
            <div class="players-grid">
                <Player
                    v-for="player in players"
                    :player="player"
                    :key="player.name"
                    :onBeforeReveal="showTeamRevealAnimation"
                />
            </div>
        </section>

        <section class="groups-section">
            <h2>Faza Grupowa</h2>
            <div class="group-grid">
                <v-card
                    v-for="group in groups"
                    :key="group.name"
                    class="group-card"
                    rounded="xl"
                    elevation="6"
                >
                    <v-card-title class="group-title">Grupa {{ group.name }}</v-card-title>
                    <v-card-text>
                        <div class="team-list">
                            <div
                                v-for="(row, index) in groupStandings[group.name]"
                                :key="row.team.name"
                                class="team-list-item"
                                :class="qualificationClass(index)"
                            >
                                <span class="team-rank">{{ index + 1 }}</span>
                                <flag :iso="row.team.icon" />
                                <span class="team-name">{{ row.team.name }}</span>
                                <span class="team-points">{{ row.points }} pkt</span>
                                <span class="team-owner" v-if="ownerByTeam[row.team.name]">{{ ownerByTeam[row.team.name] }}</span>
                            </div>
                        </div>

                        <div class="matches-wrap">
                            <Match
                                v-for="(match, index) in group.matches"
                                :key="`${group.name}-${match.team1.name}-${match.team2.name}`"
                                :team1="match.team1"
                                :team2="match.team2"
                                :addGoalsScored="setGoalsScored"
                                :matchId="`wc-${group.name}-${index}`"
                                storagePrefix="worldcup-match-"
                            />
                        </div>
                    </v-card-text>
                </v-card>
            </div>
        </section>

        <section class="knockout-section">
            <h2>Faza Pucharowa</h2>
            <p class="knockout-hint">
                Drabinka tworzy sie automatycznie z wynikow grup: awansuja dwie najlepsze druzyny z kazdej grupy oraz osiem najlepszych z trzecich miejsc, dokladnie wedlug zasad MS 2026.
            </p>
            <WorldCupKnockout :round32="seededRound32" :addGoalsScored="setGoalsScored" />
        </section>

        <section class="results-section" v-if="isDrafted">
            <Results :players="players" />
        </section>

        <transition name="reveal-fade">
            <div v-if="revealActive" class="reveal-overlay">
                <div class="reveal-glow reveal-glow-left" />
                <div class="reveal-glow reveal-glow-right" />

                <div class="reveal-content">
                    <div class="reveal-header">
                        <span class="reveal-kicker">Losowanie</span>
                        <h2>Nowy Kraj</h2>
                        <p>{{ revealCurrentOwner }}</p>
                    </div>

                    <transition name="card-pop" mode="out-in">
                        <article v-if="revealItem" :key="`${revealItem.owner}-${revealItem.team.name}`" class="reveal-card">
                            <div class="owner-chip">{{ revealItem.owner }}</div>
                            <div class="team-line">
                                <h3>
                                    {{ revealTypedName }}
                                    <span class="typing-caret" v-if="isTypingName">|</span>
                                </h3>
                                <transition name="flag-pop">
                                    <flag v-if="revealShowFlag" :iso="revealItem.team.icon" class="reveal-flag" />
                                </transition>
                            </div>
                            <div class="team-rating" v-if="revealShowFlag">
                                <v-rating
                                    :model-value="revealItem.team.rating"
                                    half-increments
                                    readonly
                                    color="amber"
                                    size="22"
                                />
                            </div>
                        </article>
                    </transition>

                    <div class="reveal-actions">
                        <v-btn
                            color="white"
                            variant="outlined"
                            rounded="xl"
                            prepend-icon="mdi-skip-forward"
                            @click="skipRevealAnimation"
                        >
                            Skip Animation
                        </v-btn>
                    </div>
                </div>
            </div>
        </transition>
    </div>
</template>
<script>
import Player from '@/components/Player.vue';
import Match from '@/components/Match.vue';
import Results from '@/components/Results.vue';
import WorldCupKnockout from '@/components/WorldCupKnockout.vue';

// Grupy i druzyny zgodne z losowaniem finalowym MS 2026 (5 grudnia 2025).
const WORLD_CUP_GROUPS = {
    A: [
        { name: 'Meksyk', rating: 4, icon: 'mx' },
        { name: 'Korea Poludniowa', rating: 4, icon: 'kr' },
        { name: 'Czechy', rating: 3.5, icon: 'cz' },
        { name: 'RPA', rating: 3, icon: 'za' }
    ],
    B: [
        { name: 'Kanada', rating: 4, icon: 'ca' },
        { name: 'Szwajcaria', rating: 4.5, icon: 'ch' },
        { name: 'Katar', rating: 3, icon: 'qa' },
        { name: 'Bosnia i Hercegowina', rating: 3.5, icon: 'ba' }
    ],
    C: [
        { name: 'Brazylia', rating: 5, icon: 'br' },
        { name: 'Maroko', rating: 4.5, icon: 'ma' },
        { name: 'Szkocja', rating: 4, icon: 'gb-sct' },
        { name: 'Haiti', rating: 2.5, icon: 'ht' }
    ],
    D: [
        { name: 'Stany Zjednoczone', rating: 4, icon: 'us' },
        { name: 'Australia', rating: 3.5, icon: 'au' },
        { name: 'Paragwaj', rating: 3.5, icon: 'py' },
        { name: 'Turcja', rating: 4, icon: 'tr' }
    ],
    E: [
        { name: 'Niemcy', rating: 5, icon: 'de' },
        { name: 'Ekwador', rating: 4, icon: 'ec' },
        { name: 'Wybrzeze Kosci Sloniowej', rating: 4, icon: 'ci' },
        { name: 'Curacao', rating: 2.5, icon: 'cw' }
    ],
    F: [
        { name: 'Holandia', rating: 5, icon: 'nl' },
        { name: 'Japonia', rating: 4, icon: 'jp' },
        { name: 'Tunezja', rating: 3.5, icon: 'tn' },
        { name: 'Szwecja', rating: 4, icon: 'se' }
    ],
    G: [
        { name: 'Belgia', rating: 4.5, icon: 'be' },
        { name: 'Iran', rating: 4, icon: 'ir' },
        { name: 'Egipt', rating: 4, icon: 'eg' },
        { name: 'Nowa Zelandia', rating: 3, icon: 'nz' }
    ],
    H: [
        { name: 'Hiszpania', rating: 5, icon: 'es' },
        { name: 'Urugwaj', rating: 4.5, icon: 'uy' },
        { name: 'Zielony Przyladek', rating: 3, icon: 'cv' },
        { name: 'Arabia Saudyjska', rating: 3, icon: 'sa' }
    ],
    I: [
        { name: 'Francja', rating: 5, icon: 'fr' },
        { name: 'Senegal', rating: 4.5, icon: 'sn' },
        { name: 'Norwegia', rating: 4, icon: 'no' },
        { name: 'Irak', rating: 3, icon: 'iq' }
    ],
    J: [
        { name: 'Argentyna', rating: 5, icon: 'ar' },
        { name: 'Austria', rating: 4, icon: 'at' },
        { name: 'Algieria', rating: 4, icon: 'dz' },
        { name: 'Jordania', rating: 3, icon: 'jo' }
    ],
    K: [
        { name: 'Portugalia', rating: 5, icon: 'pt' },
        { name: 'Kolumbia', rating: 4.5, icon: 'co' },
        { name: 'Uzbekistan', rating: 3, icon: 'uz' },
        { name: 'DR Konga', rating: 3.5, icon: 'cd' }
    ],
    L: [
        { name: 'Anglia', rating: 5, icon: 'gb-eng' },
        { name: 'Chorwacja', rating: 4.5, icon: 'hr' },
        { name: 'Panama', rating: 3, icon: 'pa' },
        { name: 'Ghana', rating: 3.5, icon: 'gh' }
    ]
};

const ALL_TEAMS = Object.values(WORLD_CUP_GROUPS).reduce((acc, teams) => acc.concat(teams), []);

const WORLDCUP_STATE_STORAGE_KEY = 'worldcup-state-v1';
const WORLDCUP_MATCH_STORAGE_PREFIX = 'worldcup-match-';

// Eligible groups for each round-of-32 slot that hosts a best third-placed team (MS 2026).
const THIRD_PLACE_SLOTS = [
    { num: 74, eligible: ['A', 'B', 'C', 'D', 'F'] },
    { num: 77, eligible: ['C', 'D', 'F', 'G', 'H'] },
    { num: 79, eligible: ['C', 'E', 'F', 'H', 'I'] },
    { num: 80, eligible: ['E', 'H', 'I', 'J', 'K'] },
    { num: 81, eligible: ['B', 'E', 'F', 'I', 'J'] },
    { num: 82, eligible: ['A', 'E', 'H', 'I', 'J'] },
    { num: 85, eligible: ['E', 'F', 'G', 'I', 'J'] },
    { num: 87, eligible: ['D', 'E', 'I', 'J', 'L'] }
];

const createDefaultPlayers = () => ([
    { name: 'Mieszko', teams: [], goalsScored: 0 },
    { name: 'Wiktor', teams: [], goalsScored: 0 },
    { name: 'Maciek', teams: [], goalsScored: 0 }
]);

export default {
    name: 'WorldCupPage',
    components: {
        Player,
        Match,
        Results,
        WorldCupKnockout
    },
    data() {
        return {
            players: createDefaultPlayers(),
            goalsBySource: {},
            revealActive: false,
            revealItem: null,
            revealTypedName: '',
            revealShowFlag: false,
            revealTypingInProgress: false,
            revealTypingIntervalId: null,
            revealEndTimeoutId: null,
            revealResolver: null
        };
    },
    computed: {
        groups() {
            return Object.entries(WORLD_CUP_GROUPS).map(([name, teams]) => ({
                name,
                teams,
                matches: this.buildGroupMatches(teams)
            }));
        },
        isDrafted() {
            return this.players.some((player) => player.teams.length > 0);
        },
        ownerByTeam() {
            return this.players.reduce((acc, player) => {
                player.teams.forEach((team) => {
                    acc[team.name] = player.name;
                });
                return acc;
            }, {});
        },
        totalGoals() {
            return Object.values(this.goalsBySource).reduce((acc, value) => acc + value.goals, 0);
        },
        groupStandings() {
            return Object.entries(WORLD_CUP_GROUPS).reduce((acc, [name, teams]) => {
                const stats = teams.reduce((map, team) => {
                    map[team.name] = {
                        team,
                        played: 0,
                        won: 0,
                        drawn: 0,
                        lost: 0,
                        goalsFor: 0,
                        goalsAgainst: 0,
                        points: 0
                    };
                    return map;
                }, {});

                this.buildGroupMatches(teams).forEach((match, index) => {
                    const goals1 = this.goalsForSource(`wc-${name}-${index}:team1`);
                    const goals2 = this.goalsForSource(`wc-${name}-${index}:team2`);
                    const home = stats[match.team1.name];
                    const away = stats[match.team2.name];

                    home.played += 1;
                    away.played += 1;
                    home.goalsFor += goals1;
                    home.goalsAgainst += goals2;
                    away.goalsFor += goals2;
                    away.goalsAgainst += goals1;

                    if (goals1 > goals2) {
                        home.won += 1;
                        home.points += 3;
                        away.lost += 1;
                    } else if (goals2 > goals1) {
                        away.won += 1;
                        away.points += 3;
                        home.lost += 1;
                    } else {
                        home.drawn += 1;
                        away.drawn += 1;
                        home.points += 1;
                        away.points += 1;
                    }
                });

                acc[name] = teams
                    .map((team) => stats[team.name])
                    .sort((a, b) => this.compareStandings(a, b));

                return acc;
            }, {});
        },
        seededRound32() {
            const standings = this.groupStandings;
            const winner = (group) => (standings[group] ? standings[group][0].team : null);
            const runnerUp = (group) => (standings[group] ? standings[group][1].team : null);
            const third = (group) => (standings[group] ? standings[group][2].team : null);

            const rankedThirds = Object.keys(standings)
                .map((group) => ({ group, entry: standings[group][2] }))
                .filter((item) => !!item.entry)
                .sort((a, b) => this.compareStandings(a.entry, b.entry));

            const qualifiedGroups = rankedThirds.slice(0, 8).map((item) => item.group);
            const slotAssignment = this.assignThirdPlaceSlots(qualifiedGroups);
            const thirdForSlot = (slotNumber) => {
                const group = slotAssignment[slotNumber];
                return group ? third(group) : null;
            };

            return [
                { num: 73, team1: runnerUp('A'), team2: runnerUp('B') },
                { num: 74, team1: winner('E'), team2: thirdForSlot(74) },
                { num: 75, team1: winner('F'), team2: runnerUp('C') },
                { num: 76, team1: winner('C'), team2: runnerUp('F') },
                { num: 77, team1: winner('I'), team2: thirdForSlot(77) },
                { num: 78, team1: runnerUp('E'), team2: runnerUp('I') },
                { num: 79, team1: winner('A'), team2: thirdForSlot(79) },
                { num: 80, team1: winner('L'), team2: thirdForSlot(80) },
                { num: 81, team1: winner('D'), team2: thirdForSlot(81) },
                { num: 82, team1: winner('G'), team2: thirdForSlot(82) },
                { num: 83, team1: runnerUp('K'), team2: runnerUp('L') },
                { num: 84, team1: winner('H'), team2: runnerUp('J') },
                { num: 85, team1: winner('B'), team2: thirdForSlot(85) },
                { num: 86, team1: winner('J'), team2: runnerUp('H') },
                { num: 87, team1: winner('K'), team2: thirdForSlot(87) },
                { num: 88, team1: runnerUp('D'), team2: runnerUp('G') }
            ];
        },
        revealCurrentOwner() {
            return this.revealItem ? `Wlasciciel: ${this.revealItem.owner}` : '';
        },
        isTypingName() {
            return this.revealTypingInProgress;
        }
    },
    methods: {
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        normalizeGoals(goals) {
            const parsed = Number.parseInt(goals, 10);
            return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
        },
        goalsForSource(sourceKey) {
            const entry = this.goalsBySource[sourceKey];
            return entry ? this.normalizeGoals(entry.goals) : 0;
        },
        compareStandings(a, b) {
            if (b.points !== a.points) {
                return b.points - a.points;
            }

            const goalDifferenceA = a.goalsFor - a.goalsAgainst;
            const goalDifferenceB = b.goalsFor - b.goalsAgainst;

            if (goalDifferenceB !== goalDifferenceA) {
                return goalDifferenceB - goalDifferenceA;
            }

            if (b.goalsFor !== a.goalsFor) {
                return b.goalsFor - a.goalsFor;
            }

            if (b.team.rating !== a.team.rating) {
                return b.team.rating - a.team.rating;
            }

            return a.team.name.localeCompare(b.team.name);
        },
        assignThirdPlaceSlots(qualifiedGroups) {
            const assignment = {};
            const used = new Set();

            const solve = (slotIndex) => {
                if (slotIndex === THIRD_PLACE_SLOTS.length) {
                    return true;
                }

                const slot = THIRD_PLACE_SLOTS[slotIndex];

                for (const group of qualifiedGroups) {
                    if (!used.has(group) && slot.eligible.includes(group)) {
                        used.add(group);
                        assignment[slot.num] = group;

                        if (solve(slotIndex + 1)) {
                            return true;
                        }

                        used.delete(group);
                        delete assignment[slot.num];
                    }
                }

                return false;
            };

            solve(0);

            return assignment;
        },
        qualificationClass(index) {
            if (index < 2) {
                return 'qualified';
            }

            if (index === 2) {
                return 'third-place';
            }

            return '';
        },
        buildGroupMatches(teams) {
            const [team1, team2, team3, team4] = teams;
            return [
                { team1, team2 },
                { team1, team2: team3 },
                { team1, team2: team4 },
                { team1: team2, team2: team3 },
                { team1: team2, team2: team4 },
                { team1: team3, team2: team4 }
            ];
        },
        findTeamByName(teamName) {
            return ALL_TEAMS.find((team) => team.name === teamName) || null;
        },
        saveState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                window.localStorage.setItem(
                    WORLDCUP_STATE_STORAGE_KEY,
                    JSON.stringify({
                        players: this.players.map((player) => ({
                            name: player.name,
                            teams: player.teams.map((team) => team.name),
                            goalsScored: player.goalsScored
                        })),
                        goalsBySource: this.goalsBySource
                    })
                );
            } catch (error) {
                void error;
            }
        },
        loadState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const rawState = window.localStorage.getItem(WORLDCUP_STATE_STORAGE_KEY);

                if (!rawState) {
                    return;
                }

                const parsedState = JSON.parse(rawState);
                const loadedPlayers = Array.isArray(parsedState.players) ? parsedState.players : [];

                this.players = createDefaultPlayers().map((defaultPlayer, index) => {
                    const stored = loadedPlayers[index];

                    if (!stored || typeof stored !== 'object') {
                        return defaultPlayer;
                    }

                    return {
                        name: stored.name || defaultPlayer.name,
                        teams: Array.isArray(stored.teams)
                            ? stored.teams.map((teamName) => this.findTeamByName(teamName)).filter(Boolean)
                            : [],
                        goalsScored: this.normalizeGoals(stored.goalsScored)
                    };
                });

                this.goalsBySource = Object.entries(parsedState.goalsBySource || {}).reduce((acc, [key, entry]) => {
                    if (!entry || !entry.team) {
                        return acc;
                    }

                    acc[key] = {
                        team: entry.team,
                        goals: this.normalizeGoals(entry.goals)
                    };

                    return acc;
                }, {});

                this.recalculateGoalsScored();
            } catch (error) {
                void error;
            }
        },
        resetMatchStorage() {
            if (!this.isStorageAvailable()) {
                return;
            }

            const keysToRemove = Object.keys(window.localStorage).filter((key) => {
                return key.startsWith(WORLDCUP_MATCH_STORAGE_PREFIX);
            });

            keysToRemove.forEach((key) => {
                window.localStorage.removeItem(key);
            });
        },
        recalculateGoalsScored() {
            const sumForTeamNames = (teamNames) => {
                const namesSet = new Set(teamNames);
                return Object.values(this.goalsBySource).reduce((acc, entry) => {
                    return namesSet.has(entry.team) ? acc + entry.goals : acc;
                }, 0);
            };

            this.players.forEach((player) => {
                player.goalsScored = sumForTeamNames(player.teams.map((team) => team.name));
            });
        },
        resetAllGoals() {
            this.goalsBySource = {};
            this.players.forEach((player) => {
                player.goalsScored = 0;
            });
        },
        roll() {
            this.resetMatchStorage();
            this.resetRevealState();
            this.players.forEach((player) => {
                player.teams = [];
            });
            this.resetAllGoals();

            // Guarantee each group has AT MOST 2 teams from the same player.
            // Strategy: use the (2,1,1) pattern for every group. Each player is
            // the "double" owner in exactly 4 of the 12 groups → 4×2 + 8×1 = 16.
            const playerCount = this.players.length;
            const doubleRoles = [];
            for (let p = 0; p < playerCount; p++) {
                for (let i = 0; i < 4; i++) {
                    doubleRoles.push(p);
                }
            }
            // Fisher-Yates shuffle the role list
            for (let i = doubleRoles.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [doubleRoles[i], doubleRoles[j]] = [doubleRoles[j], doubleRoles[i]];
            }

            Object.values(WORLD_CUP_GROUPS).forEach((teams, groupIndex) => {
                // Shuffle teams within the group
                const shuffled = [...teams];
                for (let i = shuffled.length - 1; i > 0; i--) {
                    const j = Math.floor(Math.random() * (i + 1));
                    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
                }

                // The "double" player gets 2 teams, the other two get 1 each.
                const doublePlayer = doubleRoles[groupIndex];
                const singlePlayers = [0, 1, 2].filter((p) => p !== doublePlayer);
                this.players[doublePlayer].teams.push(shuffled[0], shuffled[1]);
                this.players[singlePlayers[0]].teams.push(shuffled[2]);
                this.players[singlePlayers[1]].teams.push(shuffled[3]);
            });
        },
        setGoalsScored(goals, team, sourceKey) {
            if (!team) {
                return;
            }

            const key = sourceKey || `team:${team}`;

            this.goalsBySource = {
                ...this.goalsBySource,
                [key]: {
                    team,
                    goals: this.normalizeGoals(goals)
                }
            };

            this.recalculateGoalsScored();
        },
        setBodyScrollLock(shouldLock) {
            if (typeof document === 'undefined') {
                return;
            }

            document.body.style.overflow = shouldLock ? 'hidden' : '';
        },
        clearRevealTimers() {
            if (this.revealTypingIntervalId) {
                window.clearTimeout(this.revealTypingIntervalId);
                this.revealTypingIntervalId = null;
            }

            if (this.revealEndTimeoutId) {
                window.clearTimeout(this.revealEndTimeoutId);
                this.revealEndTimeoutId = null;
            }
        },
        finishRevealAnimation() {
            this.clearRevealTimers();
            this.revealActive = false;
            this.setBodyScrollLock(false);

            const resolve = this.revealResolver;
            this.revealResolver = null;

            if (typeof resolve === 'function') {
                resolve();
            }
        },
        showTeamRevealAnimation(payload) {
            if (!payload || !payload.team) {
                return Promise.resolve();
            }

            if (this.revealActive) {
                this.finishRevealAnimation();
            }

            this.clearRevealTimers();
            this.revealItem = {
                owner: payload.owner || 'Gracz',
                team: payload.team
            };
            this.revealTypedName = '';
            this.revealShowFlag = false;
            this.revealTypingInProgress = true;
            this.revealActive = true;
            this.setBodyScrollLock(true);

            const fullName = this.revealItem.team.name;
            const displayChars = fullName.split('').map((char) => {
                return char === ' ' ? ' ' : '\u00B7';
            });

            const pendingIndexes = fullName
                .split('')
                .map((char, index) => {
                    return char === ' ' ? -1 : index;
                })
                .filter((index) => index >= 0);

            this.revealTypedName = displayChars.join('');

            return new Promise((resolve) => {
                this.revealResolver = resolve;

                let revealedCount = 0;

                const revealNextLetter = () => {
                    if (!pendingIndexes.length) {
                        this.clearRevealTimers();
                        this.revealTypingInProgress = false;
                        this.revealTypedName = fullName;
                        this.revealShowFlag = true;
                        this.revealEndTimeoutId = window.setTimeout(() => {
                            this.finishRevealAnimation();
                        }, 900);
                        return;
                    }

                    const randomIndex = Math.floor(Math.random() * pendingIndexes.length);
                    const targetPosition = pendingIndexes.splice(randomIndex, 1)[0];
                    displayChars[targetPosition] = fullName[targetPosition];
                    this.revealTypedName = displayChars.join('');
                    revealedCount += 1;

                    const nextDelay = revealedCount < 4 ? 800 : 400;
                    this.revealTypingIntervalId = window.setTimeout(revealNextLetter, nextDelay);
                };

                this.revealTypingIntervalId = window.setTimeout(revealNextLetter, 800);
            });
        },
        skipRevealAnimation() {
            if (this.revealItem) {
                this.revealTypedName = this.revealItem.team.name;
                this.revealShowFlag = true;
            }

            this.revealTypingInProgress = false;

            this.finishRevealAnimation();
        },
        resetRevealState() {
            this.clearRevealTimers();
            this.revealActive = false;
            this.revealItem = null;
            this.revealTypedName = '';
            this.revealShowFlag = false;
            this.revealTypingInProgress = false;
            this.revealResolver = null;
            this.setBodyScrollLock(false);
        }
    },
    mounted() {
        this.loadState();
    },
    beforeUnmount() {
        this.clearRevealTimers();
        this.setBodyScrollLock(false);
    },
    watch: {
        players: {
            handler() {
                this.saveState();
            },
            deep: true
        },
        goalsBySource: {
            handler() {
                this.saveState();
            },
            deep: true
        }
    }
};
