<template>
    <div class="match-row">
        <div class="team-side">
            <flag :iso="team1.icon" />
            <span class="team-name">{{ team1.name }}</span>
        </div>
        <v-text-field
            v-model.number="score1"
            label="Gole"
            variant="outlined"
            hide-details
            type="number"
            min="0"
            class="score-input"
            @update:modelValue="(value) => onScoreChange(value, team1, 'team1')"
        />
        <span class="separator">:</span>
        <v-text-field
            v-model.number="score2"
            label="Gole"
            variant="outlined"
            hide-details
            type="number"
            min="0"
            class="score-input"
            @update:modelValue="(value) => onScoreChange(value, team2, 'team2')"
        />
        <div class="team-side team-side-right">
            <span class="team-name">{{ team2.name }}</span>
            <flag :iso="team2.icon" />
        </div>
    </div>
</template>
<script>
export default {
    name: 'Match',
    props: {
        team1: {
            type: Object,
            required: true
        },
        team2: {
            type: Object,
            required: true
        },
        addGoalsScored: {
            type: Function,
            required: true
        },
        matchId: {
            type: String,
            default: 'match'
        },
        storagePrefix: {
            type: String,
            default: 'tournament-match-'
        }
    },
    data() {
        return {
            score1: 0,
            score2: 0
        };
    },
    computed: {
        storageKey() {
            return `${this.storagePrefix}${this.matchId}-${this.team1.name}-vs-${this.team2.name}-v1`;
        }
    },
    methods: {
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        saveMatchScore() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                window.localStorage.setItem(
                    this.storageKey,
                    JSON.stringify({
                        score1: this.normalizeGoals(this.score1),
                        score2: this.normalizeGoals(this.score2)
                    })
                );
            } catch (error) {
                void error;
            }
        },
        loadMatchScore() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const raw = window.localStorage.getItem(this.storageKey);

                if (!raw) {
                    this.addGoalsScored(0, this.team1.name, `${this.matchId}:team1`);
                    this.addGoalsScored(0, this.team2.name, `${this.matchId}:team2`);
                    return;
                }

                const parsed = JSON.parse(raw);
                this.score1 = this.normalizeGoals(parsed.score1);
                this.score2 = this.normalizeGoals(parsed.score2);

                this.addGoalsScored(this.score1, this.team1.name, `${this.matchId}:team1`);
                this.addGoalsScored(this.score2, this.team2.name, `${this.matchId}:team2`);
            } catch (error) {
                void error;
            }
        },
        normalizeGoals(value) {
            const parsed = Number.parseInt(value, 10);
            return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
        },
        onScoreChange(value, team, side) {
            if (!team) {
                return;
            }

            this.addGoalsScored(this.normalizeGoals(value), team.name, `${this.matchId}:${side}`);
        }
    },
    mounted() {
        this.loadMatchScore();
    },
    watch: {
        score1() {
            this.saveMatchScore();
        },
        score2() {
            this.saveMatchScore();
        }
    }
}
</script>
<style scoped>
.match-row {
    display: grid;
    grid-template-columns: 1fr 84px auto 84px 1fr;
    align-items: center;
    gap: 8px;
    width: 100%;
}

.team-side {
    display: flex;
    align-items: center;
    gap: 8px;
    min-width: 0;
}

.team-side-right {
    justify-content: flex-end;
}

.team-name {
    font-size: 0.9rem;
    font-weight: 600;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.separator {
    font-size: 1.3rem;
    font-weight: 700;
}

.score-input {
    max-width: 84px;
}

@media (max-width: 560px) {
    .match-row {
        grid-template-columns: 1fr;
        gap: 6px;
    }

    .separator {
        display: none;
    }

    .team-side-right {
        justify-content: flex-start;
    }
}
</style>